def gen(rng, size):
    n = max(1, min(size, 4000))
    max_x = min(50000, max(3 * n, 10))
    used = set()
    queries = []
    for _ in range(n):
        if rng.random() < 0.45:
            placed = False
            for _try in range(50):
                x = rng.randint(1, max_x)
                if x not in used:
                    used.add(x)
                    queries.append([1, x])
                    placed = True
                    break
            if not placed:
                x = rng.randint(1, max_x)
                sz = rng.randint(1, max_x)
                queries.append([2, x, sz])
        else:
            x = rng.randint(1, max_x)
            sz = rng.randint(1, max_x)
            queries.append([2, x, sz])
    if not any(q[0] == 2 for q in queries):
        queries.append([2, max_x, 1])
    return [queries]

