class Solution:
    def getResults(self, queries):
        obstacle_set = set()
        res = []
        for q in queries:
            if q[0] == 1:
                obstacle_set.add(q[1])
            else:
                x, sz = q[1], q[2]
                pts = sorted(p for p in obstacle_set if p <= x)
                prev = 0
                maxgap = 0
                for p in pts:
                    if p - prev > maxgap:
                        maxgap = p - prev
                    prev = p
                if x - prev > maxgap:
                    maxgap = x - prev
                res.append(maxgap >= sz)
        return res

