import bisect

class Solution:
    def getResults(self, queries):
        obs = []
        res = []
        for q in queries:
            if q[0] == 1:
                bisect.insort(obs, q[1])
            else:
                x, sz = q[1], q[2]
                idx = bisect.bisect_right(obs, x)
                prev = 0
                maxgap = 0
                for i in range(idx):
                    gap = obs[i] - prev
                    if gap > maxgap:
                        maxgap = gap
                    prev = obs[i]
                gap = x - prev
                if gap > maxgap:
                    maxgap = gap
                res.append(maxgap >= sz)
        return res

