var getResults = function(queries) {
    const obs = [];
    function insort(x) {
        let lo = 0, hi = obs.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (obs[mid] < x) lo = mid + 1; else hi = mid;
        }
        obs.splice(lo, 0, x);
    }
    function bisectRight(x) {
        let lo = 0, hi = obs.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (obs[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    const res = [];
    for (const q of queries) {
        if (q[0] === 1) {
            insort(q[1]);
        } else {
            const x = q[1], sz = q[2];
            const idx = bisectRight(x);
            let prev = 0;
            let maxgap = 0;
            for (let i = 0; i < idx; i++) {
                const gap = obs[i] - prev;
                if (gap > maxgap) maxgap = gap;
                prev = obs[i];
            }
            const gap = x - prev;
            if (gap > maxgap) maxgap = gap;
            res.push(maxgap >= sz);
        }
    }
    return res;
};
